        const finHeights = [0.22, 0.28, 0.32, 0.28, 0.24, 0.2, 0.16, 0.12, 0.09];
        const finBaseWidths = [0.045, 0.052, 0.058, 0.052, 0.046, 0.038, 0.03, 0.024, 0.018];
