          tatter.position.set(Math.sin(ang) * 0.33, 0.18, Math.cos(ang) * 0.33);
          tatter.rotation.y = ang;
          tatter.rotation.x = 0.28 + (e % 2) * 0.15;
          dwHover.add(tatter);
          // Sand particle at tip (every other)
