          tuft.position.set(Math.sin(ang) * r, 1.47 + Math.sin(ft) * 0.07, 0.18 + Math.cos(ang) * r * 0.7);
          tuft.rotation.set(Math.sin(ft) * 0.6, ang, Math.cos(ft) * 0.5);
