            skLegGroup.add(fetlock);
            // Golden hoof
            const hoof = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.07, 0.04, 44), hoofMat);
            hoof.position.y = -0.7;
            skLegGroup.add(hoof);
            // Golden hoof band
            const hoofBand = new THREE.Mesh(new THREE.TorusGeometry(0.065, 0.008, 66, 98), goldMat);
