      const fpY = 1.5 + Math.random() * 6;
      floatPlat.position.set((Math.random() - 0.5) * w * 0.7, fpY, (Math.random() - 0.5) * d * 0.7);
      floatPlat.rotation.set((Math.random() - 0.5) * 0.15, Math.random(), (Math.random() - 0.5) * 0.15);
      this._scene.add(floatPlat);
